import { Avatar, Badge, Card, Col, Image, Row } from "antd"
import { Collapse } from "antd"
import React, { useEffect, useState } from "react"
import logo from "src/assets/images/logo/logo3.png"
import bgCard from "src/assets/images/Rectangle19.png"
import "./FlipCard.scss"
import UserService from "src/services/UserService"
import {
  CalendarOutlined,
  DownOutlined,
  EditOutlined,
  EnvironmentOutlined,
  MailOutlined,
  PhoneOutlined,
  RightOutlined,
} from "@ant-design/icons"
import ButtonCustom from "src/components/MyButton/Button"
import TitleCustom from "src/components/TitleCustom"
import ModalChangeInfo from "../../MyAccount/components/ModalChangeInfo"

function CardInfo() {
  // Responsive: kiểm tra màn mobile
  const isMobile = typeof window !== "undefined" && window.innerWidth <= 480
  // Hiển thị giới tính chuẩn
  const getGenderText = gender => {
    if (gender === 1) return "Nam"
    if (gender === 2) return "Nữ"
    return "Không xác định"
  }
  const [userData, setUserData] = useState(null)
  const [isModalVisible, setIsModalVisible] = useState(false)

  const handleShowModal = () => {
    setIsModalVisible(true)
  }

  const handleCancel = () => {
    setIsModalVisible(false)
  }

  const handleSuccess = updatedData => {
    setUserData(updatedData)
    setIsModalVisible(false)
  }

  const displayText = value => value || "Chưa có thông tin"

  const basic = userData?.BasicInfo || {}
  const RepresentativeInfo = userData?.RepresentativeInfo || {}
  const memberType = userData?.MemberType
  const memberId = userData?.MemberID

  const DOMAIN_PROD = "https://qlhv.hhsk.h2qsolution.com"
  const isLocal =
    window.location.origin.includes("localhost") ||
    window.location.origin.includes("127.0.0.1")

  const domain = isLocal ? window.location.origin : DOMAIN_PROD

  const qrUrl = `${domain}/scan-qr?memberId=${memberId}&memberType=${memberType}`

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await UserService.getInforUser()
        if (res?.isOk) {
          setUserData(res.Object)
        }
      } catch (error) {
        console.error("Lỗi khi tải thông tin:", error)
      } finally {
        console.error("Lỗi khi tải thông tin:")
      }
    }
    fetchData()
  }, [])

  return (
    <div className="info-container">
      <TitleCustom>Thông tin cá nhân</TitleCustom>

      <Row gutter={[30, 24]}>
        <Col
          span={6}
          style={{
            order:
              typeof window !== "undefined" && window.innerWidth <= 480 ? 2 : 0,
            width:
              typeof window !== "undefined" && window.innerWidth <= 480
                ? "100%"
                : undefined,
          }}
        >
          <Card
            cover={
              <div className="flex flex-col items-center py-6">
                <Avatar
                  size={96}
                  src={basic.AvatarUrl}
                  style={{ marginBottom: 16 }}
                >
                  NV
                </Avatar>
                <h3 className="text-xl font-semibold">
                  {basic.OrganizationName || "Chưa có thông tin"}
                </h3>
                <Badge
                  color="cyan"
                  style={{ marginTop: 8 }}
                  text={basic.PackageName || "Chưa có thông tin"}
                />
              </div>
            }
          >
            <div className="space-y-3 text-sm">
              <div className="flex items-center gap-2">
                <MailOutlined />
                <span>
                  <strong>Email :</strong> {basic.Email || "Không có thông tin"}
                </span>
              </div>
              <div className="flex items-center gap-2">
                <PhoneOutlined />
                <span>
                  <strong>Số điện thoại :</strong>{" "}
                  {basic.PhoneNumber || "Không có thông tin"}
                </span>
              </div>
              <div className="flex items-center gap-2">
                <EnvironmentOutlined />
                <span>
                  <strong>Địa chỉ :</strong>{" "}
                  {RepresentativeInfo.Address || "Không có thông tin"}
                </span>
              </div>
              <div className="flex items-center gap-2">
                <CalendarOutlined />
                <span>
                  <strong>Ngày gia nhập :</strong>{" "}
                  {basic.DateIssue || "Không có thông tin"}
                </span>
              </div>

              {basic.IdentificationNumber ? (
                <div className="flex items-center gap-2">
                  <CalendarOutlined />
                  <span>
                    <strong>Số CCCD :</strong>
                    {basic.IdentificationNumber || "Không có thông tin"}
                  </span>
                </div>
              ) : (
                <></>
              )}
            </div>

            <ButtonCustom
              block
              type="default"
              icon={<EditOutlined />}
              style={{ marginTop: 16 }}
              onClick={handleShowModal}
            >
              Chỉnh sửa thông tin
            </ButtonCustom>
          </Card>
        </Col>
        <Col
          span={18}
          style={{
            order:
              typeof window !== "undefined" && window.innerWidth <= 480
                ? -1
                : 0,
            width:
              typeof window !== "undefined" && window.innerWidth <= 480
                ? "100%"
                : undefined,
            marginBottom:
              typeof window !== "undefined" && window.innerWidth <= 480
                ? 16
                : undefined,
          }}
        >
          <Row>
            <div className="flip-card-container">
              {/* Card 1 */}
              <Card
                hoverable
                className="card-front"
                style={{
                  backgroundImage: `url(${bgCard})`,
                  backgroundSize: "cover",
                  backgroundPosition: "center",
                }}
              >
                <div className="header-front">
                  <img src={logo} width={100} height={100} />

                  <div className="name-organization">
                    <div>HIỆP HỘI TƯ VẤN NÂNG CAO </div>
                    <div>SỨC KHỎE VIỆT NAM</div>
                  </div>
                </div>
                <div className="card-name">THẺ HỘI VIÊN</div>

                <div className="body-info">
                  <div className="member-info">
                    <div className="name">
                      {memberType === 2
                        ? displayText(basic.OrganizationName)
                        : displayText(basic.FullName)}
                    </div>
                    <div>VAHCP 0102</div>
                    <div>{displayText(basic.AccountName)}</div>
                  </div>

                  <div className="qr-code">
                    <Image
                      width={110}
                      src={`https://api.qrserver.com/v1/create-qr-code/?size=200x200&data=${encodeURIComponent(
                        qrUrl,
                      )}`}
                      style={{ borderRadius: "10px", padding: 3 }}
                      alt="QR code"
                      className="qr-info"
                    />
                  </div>
                </div>
              </Card>
            </div>
          </Row>
          <Row style={{ marginTop: 20, justifyContent: "center" }}>
            <Col span={24}>
              {isMobile ? (
                <Collapse
                  expandIcon={({ isActive }) =>
                    isActive ? (
                      <DownOutlined style={{ color: "#fff" }} />
                    ) : (
                      <RightOutlined style={{ color: "#fff" }} />
                    )
                  }
                  accordion
                  className="additional-info-card"
                >
                  <Collapse.Panel
                    header={
                      <span style={{ fontWeight: "600", color: "#fff" }}>
                        Thông tin bổ sung
                      </span>
                    }
                    key="1"
                  >
                    <div className="additional-info-grid">
                      <div className="additional-info-item">
                        <strong>Giới tính:</strong>{" "}
                        {getGenderText(basic.Gender)}
                      </div>
                      <div className="additional-info-item">
                        <strong>Ngày sinh:</strong>{" "}
                        {basic.DateOfBirth || "Không có"}
                      </div>
                      <div className="additional-info-item">
                        <strong>Nghề nghiệp:</strong>{" "}
                        {basic.Occupation || "Không có"}
                      </div>
                      <div className="additional-info-item">
                        <strong>Địa chỉ thường trú:</strong>{" "}
                        {userData?.AddressInfo?.ResidenceAddress || "Không có"}
                      </div>
                      <div className="additional-info-item">
                        <strong>Địa chỉ tạm trú:</strong>{" "}
                        {userData?.AddressInfo?.RecentAddress || "Không có"}
                      </div>
                    </div>
                  </Collapse.Panel>
                </Collapse>
              ) : (
                <Card
                  title="Thông tin bổ sung"
                  bordered={false}
                  className="additional-info-card"
                >
                  <div className="additional-info-grid">
                    <div className="additional-info-item">
                      <strong>Giới tính:</strong> {getGenderText(basic.Gender)}
                    </div>
                    <div className="additional-info-item">
                      <strong>Ngày sinh:</strong>{" "}
                      {basic.DateOfBirth || "Không có"}
                    </div>
                    <div className="additional-info-item">
                      <strong>Nghề nghiệp:</strong>{" "}
                      {basic.Occupation || "Không có"}
                    </div>
                    <div className="additional-info-item">
                      <strong>Địa chỉ thường trú:</strong>{" "}
                      {userData?.AddressInfo?.ResidenceAddress || "Không có"}
                    </div>
                    <div className="additional-info-item">
                      <strong>Địa chỉ tạm trú:</strong>{" "}
                      {userData?.AddressInfo?.RecentAddress || "Không có"}
                    </div>
                  </div>
                </Card>
              )}
            </Col>
          </Row>
        </Col>
      </Row>
      <ModalChangeInfo
        visible={isModalVisible}
        userData={userData}
        onCancel={handleCancel}
        onSuccess={handleSuccess}
      />
    </div>
  )
}

export default CardInfo
