import {
  FileTextOutlined,
  HomeOutlined,
  IdcardOutlined,
  MailOutlined,
  PhoneOutlined,
  ShopOutlined,
  TeamOutlined,
  UserOutlined
} from "@ant-design/icons"
import { DatePicker, Form, Input, Modal } from "antd"
import dayjs from "dayjs"
import { useEffect } from "react"
import notice from "src/components/Notice"
import UserService from "src/services/UserService"
import "./ModalChangeInfo.scss"

const ModalChangeInfo = ({ visible, userData, onCancel, onSuccess }) => {
  const [form] = Form.useForm()
  const isBusiness = userData?.MemberType === 2

  useEffect(() => {
    if (userData && visible) {
      const newValues = isBusiness
        ? {
            OrganizationName: userData?.BasicInfo?.OrganizationName,
            TaxCode: userData?.BasicInfo?.TaxCode,
            DateIssue: userData?.BasicInfo?.DateIssue
              ? dayjs(userData.BasicInfo.DateIssue)
              : null,
            Email: userData?.BasicInfo?.Email,
            PhoneNumber: userData?.BasicInfo?.PhoneNumber,
            Address: userData?.AddressInfo?.RecentAddress,
            RepresentativeName: userData?.RepresentativeInfo?.FullName,
            RepresentativePhoneNumber:
              userData?.RepresentativeInfo?.PhoneNumber,
            RepresentativePosition: userData?.RepresentativeInfo?.Position,
            RepresentativeIdentification:
              userData?.RepresentativeInfo?.IdentificationNumber,
            RepresentativeAddress: userData?.RepresentativeInfo?.Address,
          }
        : {
            FullName: userData?.BasicInfo?.FullName,
            PhoneNumber: userData?.BasicInfo?.PhoneNumber,
            Email: userData?.BasicInfo?.Email,
            Identification: userData?.BasicInfo?.IdentificationNumber,
            Occupation: userData?.BasicInfo?.Occupation,
            Address: userData?.AddressInfo?.RecentAddress,
          }

      form.resetFields()
      form.setFieldsValue(newValues)
    }
  }, [userData, visible])

  const handleOk = async () => {
    try {
      const values = await form.validateFields()

      const payload = {
        Avatar: userData?.BasicInfo?.AvatarUrl || "",
        Email: values.Email,
        PhoneNumber: values.PhoneNumber,
        Address: values.Address,
        WardID: userData?.AddressInfo?.WardId || 0,
        DistrictID: userData?.AddressInfo?.DistrictId || 0,
        ProvinceID: userData?.AddressInfo?.ProvinceId || 0,
        MemberType: userData?.MemberType,
        Individual: isBusiness
          ? {}
          : {
              FullName: values.FullName,
              PhoneNumber: values.PhoneNumber,
              Occupation: values.Occupation || "",
              Identification: values.Identification,
            },
        Business: isBusiness
          ? {
              OrganizationName: values.OrganizationName,
              TaxCode: values.TaxCode,
              DateIssue:
                values.DateIssue && dayjs.isDayjs(values.DateIssue)
                  ? values.DateIssue.format("YYYY-MM-DDTHH:mm:ss.SSS[Z]")
                  : null,
              RepresentativeName: values.RepresentativeName,
              RepresentativeAvatar:
                userData?.RepresentativeInfo?.AvatarUrl || "",
              RepresentativePhoneNumber: values.RepresentativePhoneNumber,
              RepresentativePosition: values.RepresentativePosition,
              RepresentativeIdentification: values.RepresentativeIdentification,
              RepresentativeAddress: values.RepresentativeAddress,
            }
          : {},
      }

      const res = await UserService.changeInfor(payload)
      if (res?.isOk) {
        notice({ msg: "Cập nhật thông tin thành công", isSuccess: true })
        form.resetFields()

        const updatedUserData = {
          ...userData,
          BasicInfo: {
            ...userData.BasicInfo,
            Email: values.Email,
            PhoneNumber: values.PhoneNumber,
            ...(isBusiness
              ? {
                  OrganizationName: values.OrganizationName,
                  TaxCode: values.TaxCode,
                  DateIssue:
                    values.DateIssue && dayjs.isDayjs(values.DateIssue)
                      ? values.DateIssue.format("DD/MM/YYYY")
                      : null,
                }
              : {
                  FullName: values.FullName,
                  Occupation: values.Occupation || "",
                  Identification: values.Identification,
                }),
          },
          AddressInfo: {
            ...userData.AddressInfo,
            RecentAddress: values.Address,
          },
          RepresentativeInfo: isBusiness
            ? {
                ...userData.RepresentativeInfo,
                FullName: values.RepresentativeName,
                PhoneNumber: values.RepresentativePhoneNumber,
                Position: values.RepresentativePosition,
                IdentificationNumber: values.RepresentativeIdentification,
                Address: values.RepresentativeAddress,
              }
            : userData.RepresentativeInfo,
        }

        onSuccess(updatedUserData)
      } else {
        notice({ msg: res?.message || "Cập nhật thất bại", isSuccess: false })
      }
    } catch (error) {
      console.error("Lỗi cập nhật:", error)
      notice({ msg: "Đã xảy ra lỗi, vui lòng thử lại", isSuccess: false })
    }
  }

  return (
    <Modal
      title="Chỉnh sửa thông tin"
      open={visible}
      onOk={handleOk}
      onCancel={onCancel}
      okText="Lưu"
      cancelText="Hủy"
      width={850}
      className="modal-change-info"
    >
      <Form form={form} layout="vertical" name="changeInfoForm">
        {isBusiness ? (
          <div className="business-form-container">
            <div className="business-info-column">
              <h3>Thông tin doanh nghiệp</h3>
              <Form.Item
                name="OrganizationName"
                label="Tên doanh nghiệp"
                rules={[{ required: true, message: "Vui lòng nhập tên DN" }]}
              >
                <Input prefix={<ShopOutlined />} className="input-field" />
              </Form.Item>
              <Form.Item
                name="TaxCode"
                label="Mã số thuế"
                rules={[{ required: true, message: "Vui lòng nhập MST" }]}
              >
                <Input prefix={<FileTextOutlined />} className="input-field" />
              </Form.Item>
              <Form.Item
                name="DateIssue"
                label="Ngày cấp giấy phép"
                rules={[{ required: true, message: "Vui lòng chọn ngày cấp" }]}
              >
                <DatePicker
                  format="DD/MM/YYYY"
                  className="input-field"
                  allowClear
                  style={{ width: "100%" }}
                />
              </Form.Item>
              <Form.Item
                name="Email"
                label="Email doanh nghiệp"
                rules={[
                  {
                    required: true,
                    type: "email",
                    message: "Email không hợp lệ",
                  },
                ]}
              >
                <Input prefix={<MailOutlined />} className="input-field" />
              </Form.Item>
              <Form.Item
                name="PhoneNumber"
                label="SĐT doanh nghiệp"
                rules={[
                  { required: true, message: "Vui lòng nhập SĐT" },
                  {
                    pattern: /^[0-9]{10}$/,
                    message: "SĐT phải gồm đúng 10 số",
                  },
                ]}
              >
                <Input prefix={<PhoneOutlined />} className="input-field" />
              </Form.Item>
              <Form.Item
                name="Address"
                label="Địa chỉ doanh nghiệp"
                rules={[{ required: true, message: "Vui lòng nhập địa chỉ" }]}
              >
                <Input prefix={<HomeOutlined />} className="input-field" />
              </Form.Item>
            </div>
            <div className="representative-info-column">
              <h3>Thông tin người đại diện</h3>
              <Form.Item
                name="RepresentativeName"
                label="Tên người đại diện"
                rules={[
                  { required: true, message: "Vui lòng nhập tên đại diện" },
                ]}
              >
                <Input prefix={<UserOutlined />} className="input-field" />
              </Form.Item>
              <Form.Item
                name="RepresentativePhoneNumber"
                label="SĐT người đại diện"
                rules={[
                  { required: true, message: "Vui lòng nhập SĐT đại diện" },
                ]}
              >
                <Input prefix={<PhoneOutlined />} className="input-field" />
              </Form.Item>
              <Form.Item
                name="RepresentativePosition"
                label="Chức vụ"
                rules={[{ required: true, message: "Vui lòng nhập chức vụ" }]}
              >
                <Input prefix={<TeamOutlined />} className="input-field" />
              </Form.Item>
              <Form.Item
                name="RepresentativeIdentification"
                label="CCCD người đại diện"
                rules={[{ required: true, message: "Vui lòng nhập CCCD" }]}
              >
                <Input prefix={<IdcardOutlined />} className="input-field" />
              </Form.Item>
              <Form.Item
                name="RepresentativeAddress"
                label="Địa chỉ người đại diện"
                rules={[{ required: true, message: "Vui lòng nhập địa chỉ" }]}
              >
                <Input prefix={<HomeOutlined />} className="input-field" />
              </Form.Item>
            </div>
          </div>
        ) : (
          <>
            <Form.Item
              name="FullName"
              label="Họ và tên"
              rules={[{ required: true, message: "Vui lòng nhập họ và tên" }]}
            >
              <Input prefix={<UserOutlined />} className="input-field" />
            </Form.Item>
            <Form.Item
              name="PhoneNumber"
              label="Số điện thoại"
              rules={[
                { required: true, message: "Vui lòng nhập SĐT" },
                { pattern: /^[0-9]{10}$/, message: "SĐT phải gồm đúng 10 số" },
              ]}
            >
              <Input prefix={<PhoneOutlined />} className="input-field" />
            </Form.Item>
            <Form.Item
              name="Email"
              label="Email"
              rules={[
                {
                  required: true,
                  type: "email",
                  message: "Email không hợp lệ",
                },
              ]}
            >
              <Input prefix={<MailOutlined />} className="input-field" />
            </Form.Item>
            <Form.Item
              name="Occupation"
              label="Nghề nghiệp"
              rules={[{ required: true, message: "Vui lòng nhập nghề nghiệp" }]}
            >
              <Input prefix={<TeamOutlined />} className="input-field" />
            </Form.Item>
            <Form.Item
              name="Address"
              label="Địa chỉ liên hệ"
              rules={[{ required: true, message: "Vui lòng nhập địa chỉ" }]}
            >
              <Input prefix={<HomeOutlined />} className="input-field" />
            </Form.Item>
          </>
        )}
      </Form>
    </Modal>
  )
}

export default ModalChangeInfo
